;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@command title="Which button will you press?" cancel=true
@select text="21Ｆ" exp='tf.result = ["ラドミラの塔21Ｆ", "down"]'
@select text="17Ｆ" exp='tf.result = ["ラドミラの塔17Ｆ", "down"]'
@select text="No" exp='tf.result = []'
[ask]
@elevator map=&'tf.result[0]' lift=&'tf.result[1]' cond='tf.result[0] !== void'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger || (onUseEventItem && curItem == o.悪魔の彫像)

[if exp='game.onObjectTrigger']
	@notice text="There is a picture of a devil on the stone tablet."
	[eventoff]
[endif]
@changewall way=s click=false
@changefloor pimg="pd_demon"
@eval exp='game.party.ejectItem(o.悪魔の彫像)'
@notice text="I placed a devil statue on the pedestal!"
@delevent
@call target=*_appear_warp

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger || (onUseEventItem && curItem == o.スライムの彫像)

[if exp='game.onObjectTrigger']
