[eventoff]
;-------------------------------------------------------------------------------
*_appear_warp
@wait time=800
@return cond='game.map.events.has(2) || game.map.events.has(3)'
@return cond='game.map.events.has(4) || game.map.events.has(5) || game.map.events.has(6)'
@se f=shuwa2
@eval exp='game.map.setWarp(4, 8, "A", "warp")'
@wait time=800
@notice text="I heard something moving outside the room!"
@return
;-------------------------------------------------------------------------------
